def gen(rng, size):
    n = max(2, min(size, 100))
    digit = str(rng.randint(1, 9))
    chars = []
    for _ in range(n):
        if rng.random() < 0.4:
            chars.append(digit)
        else:
            chars.append(str(rng.randint(1, 9)))
    if digit not in chars:
        chars[rng.randrange(n)] = digit
    return [''.join(chars), digit]

