var removeDigit = function(number, digit) {
    let last = -1;
    for (let i = 0; i < number.length; i++) {
        if (number[i] === digit) {
            last = i;
            if (i + 1 < number.length && number[i + 1] > digit) {
                return number.slice(0, i) + number.slice(i + 1);
            }
        }
    }
    return number.slice(0, last) + number.slice(last + 1);
};
